have c := CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.meanWeightedSupport 4 CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourCohortSupport CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourHorizonPositive CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourSupportNonempty CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourCohortShare CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourCohortLimitBaseline CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourCohortGamma CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.zeroEffects4;
have H := CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.collapsedNuisanceSubspace 4 CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourCohortSupport;
have R := fun z => CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fourResidualTable (↑z.1) z.2;
∀ h ∈ H, c.ip R h = 0

∀ (T : ℕ) (C : Finset (CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.Cohort T)) (hT : 0 < T) (hC : C.Nonempty) (pi : CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.Cohort T → CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.OpenUnit) (barB : CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.Cohort T → CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.PosReal) (gamma : Fin T → ℝ) (delta : CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.Cell T → ℝ) (k : CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.Cohort T) (hk : k ∈ C) (s : Fin T),
  CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.treatmentIndicator T k s = 1 →
    CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.CollapsedDesignRank T C pi →
      have W := CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.weightedFWLResidual T C hT hC pi barB gamma delta (⟨k, hk⟩, s);
      have denominator := CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.fwlEnergy T C hT hC pi barB gamma delta;
      have derivative := CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.limitingCellMass T pi k * CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.untreatedMean T barB gamma k s * Real.exp (delta (k, s)) * W / denominator;
      HasDerivAt (fun x => CausalSmith.Panel.PANEL_PpmlForbiddenComparison_Research.betaStar T C pi barB gamma (Function.update delta (k, s) x)) derivative (delta (k, s)) ∧ 0 < denominator ∧ (derivative < 0 ↔ W < 0) ∧ (derivative = 0 ↔ W = 0) ∧ (0 < derivative ↔ 0 < W)

